import React, { useEffect, useMemo, useState } from "react"; 
import { useParams, useLocation } from "react-router-dom"; 

import { 
    Card,
    CardContent,
    CardContentText,
    CardContentSubtitle,
    CardContentTitle,
    CardImage,
    CardRow,
    Content, 
    CardContentIconPin,
    CardLocale,
    CardFiends,
    CardContentIconUsers,
    CardTitle,
    CardText,
    BodyCard
} from "./styled";

import ContainerLandpage from "containers/Landpage";

import { Col, Row } from "reactstrap";

import { API_ENDPOINT } from "services/api";

import { ReadMyFriends } from 'services/me'
import { ReadUserPosts } from 'services/posts'
import { Count } from 'services/follows';

import { normalizeStrapiList, parseStrapiImage } from "utils";
import { mapPost } from 'utils/maps'
import moment from "moment/moment";

export default function Landpage(){ 
    
    
  const location = useLocation();
  const searchParams = new URLSearchParams(location.search);
  const userId = searchParams.get('u');
    
    const [loading, setLoading] = useState(false)
    const [follows, setFollows] = useState(0)
    const [posts, setPosts] = useState([])

    const [uProfile, setUProfile] = useState(null)
    

    const userProfile = useMemo(() => {
        return {
            ...uProfile,
            link: `${ API_ENDPOINT?.substring(0, API_ENDPOINT?.length - 4 ) }/profile?u=${uProfile?.id}`
        }
    }, [uProfile])

    const init = async () => {
        if(userProfile?.id){
            setLoading(true)
            if(userProfile?.id){
                const result = await ReadUserPosts(userProfile?.id)
                const normalPosts = normalizeStrapiList(result)
                    .map(mapPost)
                    .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
                setPosts(normalPosts)
    
                const resFollow = await Count(userProfile?.id)
                setFollows(resFollow?.meta?.pagination?.total || 0)
    
            }
            setLoading(false)
        }
    } 

    const readProfile = async () => {
        if(userId){
            setLoading(true)
            const result = await ReadMyFriends(userId)
            if(result?.id){
                console.log("Founded profile", result)
                setUProfile(result)
            }
        }
    }
    

    useEffect(() => {
        init()
    }, [userProfile])

    useEffect(() => {
        readProfile()
    }, [userId])
 
    return ( 
        <ContainerLandpage> 
            <Content>
                <Row>
                    <Col lg={{ size:4, offset: 4 }} md={{ size:6, offset: 3 }}>
                        <Card>
                            <CardRow>
                                <CardImage image={userProfile?.avatar?.url ? parseStrapiImage(userProfile?.avatar?.url) : null } />
                                <CardContent>
                                    <CardContentTitle>{ userProfile?.name }</CardContentTitle>
                                    <CardContentSubtitle>{ userProfile?.specialty?.name } { userProfile?.sub_specialties?.[0]?.name }</CardContentSubtitle>
                                    <CardLocale>
                                        <CardContentIconPin />
                                        <CardContentText>{ userProfile?.city }{userProfile?.uf && userProfile?.city ? " / " : ""}{ userProfile?.uf }</CardContentText>
                                    </CardLocale>
                                    <CardFiends>
                                        <CardContentIconUsers />
                                        <CardContentText>{ follows } colegas</CardContentText>
                                    </CardFiends>
                                </CardContent>
                            </CardRow>
                        </Card>

                        <CardTitle>Sobre</CardTitle>
                        <Card>
                            <CardText>{ userProfile?.about }</CardText>
                        </Card>

                        <CardTitle>Endereço Profissional</CardTitle>
                        <Card>
                            <CardText link>{ userProfile?.address ? `${ userProfile?.address?.street }, ${ userProfile?.address?.number } - ${ userProfile?.address?.uf }/${ userProfile?.address?.uf }` : `` }</CardText>
                        </Card>

                        <CardTitle>Expertise e habilidades</CardTitle>
                        <Card>
                            <CardText>{ userProfile?.expertise }</CardText>
                        </Card>

                        <CardTitle>Formação acadêmica</CardTitle>
                        <Card>
                            {
                                userProfile?.academic_education?.map((item, key) => 
                                    <BodyCard key={key}>
                                        <CardContentTitle>{ item?.university?.name }</CardContentTitle>
                                        <CardText spaced>{ item?.name }</CardText>
                                        <CardText>{ moment(item?.initial)?.format("YYYY") } - { moment(item?.end)?.format("YYYY") }</CardText>
                                    </BodyCard>
                                )
                            }
                        </Card>

                        <CardTitle>Licenças e certificados</CardTitle>
                        <Card>
                            {
                                userProfile?.certificate_license?.map((item, key) => 
                                    <BodyCard key={key}>
                                        <CardContentTitle>{ item?.name }</CardContentTitle>
                                        <CardText>{ moment(item?.initial)?.format("YYYY") } - { moment(item?.end)?.format("YYYY") }</CardText>
                                    </BodyCard>
                                )
                            }
                        </Card>

                        <CardTitle>Publicações e apresentações</CardTitle>
                        <Card>
                            {
                                userProfile?.publications?.map((item, key) => 
                                    <BodyCard key={key}>
                                        <CardContentTitle>{ item?.name }</CardContentTitle>
                                        <CardText>{ moment(item?.initial)?.format("YYYY") } - { moment(item?.end)?.format("YYYY") }</CardText>
                                    </BodyCard>
                                )
                            }
                        </Card>

                        <CardTitle>Membro</CardTitle>
                        <Card>
                            {
                                userProfile?.members?.map((item, key) => 
                                    <BodyCard key={key}>
                                        <CardContentTitle>{ item?.title }</CardContentTitle>
                                        <CardText>{ item.name }</CardText>
                                    </BodyCard>
                                )
                            }
                        </Card>

                        <CardTitle>Links importantes</CardTitle>
                        <Card>
                            {
                                userProfile?.links?.map((item, key) => 
                                    <BodyCard key={key}>
                                        <CardContentTitle>{ item?.title }</CardContentTitle>
                                        <CardText link onClick={() => window.open(item.url)}>{ item.url }</CardText>
                                    </BodyCard>
                                )
                            }
                        </Card>

                        <CardTitle>Perfil público</CardTitle>
                        <Card>
                            <CardText link onClick={() => window.open(userProfile.link)}> { userProfile.link } </CardText>
                        </Card>


                    </Col>
                </Row>
            </Content>
        </ContainerLandpage>
    );
}