import { arrayToQueryString, objectToQueryString } from 'utils/index';
import { GET, POST, PUT, DELETE } from './api'

const table = "posts"

export const Create = async (params) => {
    return await POST(`/${ table }`, params, true);
}

export const Read = async (qs="") => {
    const query = {
        populate:[
            "user.avatar",
            "user.specialty",
            "user.sub_specialties",
            "images",
            "video",
            "post",
            "event",
            "event.address",
            "event.image",
            "job",
            "job.address",
            "post.user.avatar",
            "post.images",
            "post.video",
        ],
        pagination:{
            pageSize: 1000
        }
    }
    const queryString = objectToQueryString(query)
    return await GET(`/${ table }?${queryString}${qs}`, true);
}

export const ReadUserPosts = async (user_id) => {
    return await Read(`&filters[user]=${user_id}`)
}

export const ReadOne = async (id) => {
    return await GET(`/${ table }/${id}?populate=*`, true);
}

export const Update = async (params, id) => {
    return await PUT(`/${ table }/${id}`, params, true);
}

export const Delete = async (id) => {
    return await DELETE(`/${ table }/${ id }`, true);
} 
