import { normalizeStrapiList, normalizeStrapiRegister } from "./index"

export const mapPost = m => {
    const nPost = normalizeStrapiRegister(m?.post)
    const normalPost = nPost.id ? nPost : null

    const nJob = normalizeStrapiRegister(m?.job)
    const normalJob = nJob.id ? nJob : null
    
    const nEvent = normalizeStrapiRegister(m?.event)
    const normalEvent = nEvent.id ? nEvent : null
    
    const post = {
        video: normalPost?.video || normalizeStrapiRegister(m?.video),
        images: normalPost?.images || normalizeStrapiList(m?.images),
        text: normalPost?.text || m?.text,
    }

    return {
        ...m,
        original: m,
        post: normalPost,
        
        job: normalJob,
        event: normalEvent,
        
        user: normalizeStrapiRegister(m?.user), 
        share_user: !normalPost ? null : normalizeStrapiRegister(normalPost?.user),                    

        video: post?.video,
        image: post?.images?.[0],
        text: post.text
    }
}