import { GET, POST, PUT, DELETE } from './api'

const table = "follows"

export const Create = async (params) => {
    return await POST(`/${ table }`, params, true);
}

export const Read = async (user_id) => {
    return await GET(`/${ table }?filters[requested]=${user_id}&pagination[pageSize]=1000&populate[0]=requester.avatar&populate[1]=requester.specialty&populate[2]=requester.sub_specialties`, true);
}

export const ReadFollow = async (user_id) => {
    return await GET(`/${ table }?filters[requester]=${user_id}&pagination[pageSize]=1000&populate[0]=requested.avatar&populate[1]=requested.specialty&populate[2]=requested.sub_specialties`, true);
}

export const AlreadyFollow = async (user_id, friend_id) => {
    return await GET(`/${ table }?filters[requester]=${user_id}&filters[requested]=${friend_id}`, true);
}

export const ReadOne = async (id) => {
    return await GET(`/${ table }/${id}?populate=*`, true);
}

export const Update = async (params, id) => {
    return await PUT(`/${ table }/${id}`, params, true);
}

export const Delete = async (id) => {
    return await DELETE(`/${ table }/${ id }`, true);
} 
 

export const Count = async (user_id) => {
    return await GET(`/${ table }?filters[requested]=${user_id}&filters[requester]=${user_id}&filters[accepted]=true&pagination[pageSize]=1&pagination[withCount]=true`, true);
}